export const notes = `
  <h2>Introduction to Geography</h2>
  <p class="topic-desc">What is Geography · Key concepts · Geographical inquiry · Maps & tools</p>

  <div class="notes-card">
    <h3>1. What is Geography?</h3>
    <p><strong>Geography</strong> is the study of the Earth's landscapes, environments, peoples, and places — and the relationships between them.</p>
    <div class="example">
      <strong>Physical Geography:</strong> studies natural features — landforms, climate, vegetation, rivers, oceans<br>
      <strong>Human Geography:</strong> studies people — population, cities, economies, culture, land use<br><br>
      <strong>Why study Geography?</strong><br>
      • Understand <em>where</em> things are and <em>why</em> they are there<br>
      • Understand how human activities affect the environment<br>
      • Make informed decisions about managing Earth's resources<br>
      • Develop spatial awareness and global perspectives
    </div>
  </div>

  <div class="notes-card">
    <h3>2. The Four Key Geographical Concepts</h3>
    <div class="example">
      <strong>Space:</strong> The location of features and how they are distributed across the Earth's surface.<br>
      <em>e.g. Why are rainforests located near the equator? Why is Singapore's CBD in the south?</em><br><br>
      <strong>Place:</strong> The physical and human characteristics that give a location its identity and meaning.<br>
      <em>e.g. Singapore is known for its multicultural society, efficient transport, and cleanliness.</em><br><br>
      <strong>Environment:</strong> The surroundings in which people live — both natural (climate, soil, rivers) and human-made (buildings, roads, farms).<br>
      <em>e.g. How does deforestation change the forest environment?</em><br><br>
      <strong>Scale:</strong> The level at which we study geography — from local to national, regional, and global.<br>
      <em>e.g. Water shortage studied at local (village well), national (Singapore), and global (sub-Saharan Africa) scale.</em>
    </div>
  </div>

  <div class="notes-card">
    <h3>3. Geographical Inquiry</h3>
    <p>Geographers ask questions and carry out investigations to understand the world.</p>
    <div class="example">
      <strong>Steps of Geographical Inquiry:</strong><br>
      1. <strong>Pose questions</strong> — ask What? Where? Why? How? So what?<br>
      2. <strong>Collect data</strong> — fieldwork (primary data) or research (secondary data)<br>
      3. <strong>Analyse &amp; interpret</strong> — identify patterns, relationships, trends<br>
      4. <strong>Draw conclusions</strong> — answer the inquiry question with evidence<br>
      5. <strong>Reflect</strong> — evaluate the process and suggest further investigation<br><br>
      <strong>Primary data:</strong> collected first-hand (surveys, observations, measurements)<br>
      <strong>Secondary data:</strong> existing data (textbooks, maps, census, news reports)
    </div>
  </div>

  <div class="notes-card">
    <h3>4. Geographical Tools — Maps</h3>
    <p>A <strong>map</strong> is a flat representation of the Earth or part of it.</p>
    <div class="example">
      <strong>Essential map components (TODALS):</strong><br>
      • <strong>T</strong>itle — what the map shows<br>
      • <strong>O</strong>rientation — north arrow or compass<br>
      • <strong>D</strong>ate — when the map was made<br>
      • <strong>A</strong>uthor/Source — who made the map<br>
      • <strong>L</strong>egend/Key — explains map symbols<br>
      • <strong>S</strong>cale — ratio between map distance and actual distance<br><br>
      <strong>Types of maps:</strong><br>
      • <strong>Topographic map:</strong> shows physical features (elevation, rivers, roads) using contour lines<br>
      • <strong>Thematic map:</strong> shows a specific theme (rainfall, population density, land use)<br>
      • <strong>Choropleth map:</strong> uses shading to show data values across regions<br>
      • <strong>Dot map:</strong> uses dots to show distribution of a feature
    </div>
  </div>

  <div class="notes-card">
    <h3>5. Map Scale</h3>
    <p><strong>Scale</strong> is the ratio between distance on a map and the actual distance on the ground.</p>
    <div class="example">
      <strong>Three ways to express scale:</strong><br>
      • <strong>Linear scale (bar scale):</strong> a line drawn on the map divided into distances<br>
      • <strong>Ratio/Representative fraction:</strong> 1 : 50 000 (1 cm on map = 50 000 cm = 500 m on ground)<br>
      • <strong>Statement scale:</strong> "1 cm represents 5 km"<br><br>
      <strong>Large scale vs Small scale:</strong><br>
      • <strong>Large scale</strong> (e.g. 1 : 10 000) → shows small area, more detail<br>
      • <strong>Small scale</strong> (e.g. 1 : 1 000 000) → shows large area, less detail<br><br>
      <em>Example calculation:</em> Map scale 1 : 50 000. Map distance = 4 cm.<br>
      Actual distance = 4 × 50 000 cm = 200 000 cm = <span class="highlight">2 km</span>
    </div>
  </div>

  <div class="notes-card">
    <h3>6. Direction & Grid References</h3>
    <div class="example">
      <strong>8 compass points:</strong> N, NE, E, SE, S, SW, W, NW<br><br>
      <strong>Grid references</strong> use numbered grid lines on a map:<br>
      • <strong>4-figure grid reference:</strong> identifies a 1 km² grid square<br>
        Method: read the easting (across) first, then the northing (up)<br>
        <em>"Along the corridor, then up the stairs"</em><br>
      • <strong>6-figure grid reference:</strong> more precise, locates a point within the square<br><br>
      <strong>Latitude and Longitude:</strong><br>
      • <strong>Latitude:</strong> lines running horizontally (parallels) — measure N or S of equator (0°)<br>
      • <strong>Longitude:</strong> lines running vertically (meridians) — measure E or W of Prime Meridian (0°)<br>
      • Singapore: approximately <span class="highlight">1°N, 104°E</span>
    </div>
  </div>

  <div class="notes-card">
    <h3>7. Contour Lines (Topographic Maps)</h3>
    <p><strong>Contour lines</strong> join points of equal elevation above sea level.</p>
    <div class="example">
      <strong>Key rules:</strong><br>
      • Contour lines that are <strong>close together</strong> = steep slope<br>
      • Contour lines that are <strong>far apart</strong> = gentle slope<br>
      • Contour lines form <strong>V-shapes pointing upstream</strong> in valleys (rivers)<br>
      • Contour lines form <strong>V-shapes pointing downhill</strong> on ridges<br>
      • Contour lines <strong>never cross</strong><br>
      • <strong>Contour interval:</strong> the difference in height between consecutive contour lines
    </div>
  </div>

  <div class="notes-card">
    <h3>8. Other Geographical Tools</h3>
    <div class="example">
      <strong>Photographs:</strong><br>
      • Ground-level: taken from eye level; shows detailed features but limited area<br>
      • Aerial: taken from aircraft looking down; shows wider area and patterns<br>
      • Satellite: taken from space; shows very large areas; used in weather forecasting<br><br>
      <strong>Statistical data &amp; graphs:</strong><br>
      • Line graphs — show change over time (temperature trends)<br>
      • Bar graphs — compare quantities (rainfall by month)<br>
      • Pie charts — show proportions (land use breakdown)<br>
      • Climate graphs — combine bar (rainfall) and line (temperature) on one graph<br><br>
      <strong>GIS (Geographic Information Systems):</strong><br>
      • Computer system that stores, analyses and displays geographical data<br>
      • Can layer multiple data sets (e.g. flood risk + population density)<br>
      • Used in urban planning, disaster management, navigation
    </div>
  </div>

  <div class="notes-card">
    <h3>Quick Reference</h3>
    <div class="formula">4 key concepts: Space, Place, Environment, Scale</div>
    <div class="formula">Inquiry steps: Pose → Collect → Analyse → Conclude → Reflect</div>
    <div class="formula">Map scale 1:50 000 → 1 cm = 500 m = 0.5 km</div>
    <div class="formula">Grid reference: easting first (across), northing second (up)</div>
    <div class="formula">Close contours = steep slope · Far apart = gentle slope</div>
    <div class="formula">Singapore: 1°N, 104°E — in Southeast Asia, near equator</div>
  </div>
`

